module and_enable (
  input a,
  input b,
  input enable,
  output out
);

  wire and_result;

  and_gate and_inst (
    .a(a),
    .b(b),
    .out(and_result)
  );

  wire neg_and_result = enable;
  assign out = neg_and_result ? and_result : 1'b0;

endmodule

module and_gate (
  input a,
  input b,
  output out
);

  assign out = a & b;

endmodule
